// ============================================================
// Linear interpolation utilities for aero lookup tables
// ============================================================

// Find index and fraction for 1D interpolation
inline void interp_idx(const float* bp, int n, float val, int& i0, float& frac) {
    if (val <= bp[0]) { i0 = 0; frac = 0.0f; return; }
    if (val >= bp[n-1]) { i0 = n-2; frac = 1.0f; return; }
    for (int i = 0; i < n-1; i++) {
        if (val >= bp[i] && val <= bp[i+1]) {
            i0 = i;
            frac = (val - bp[i]) / (bp[i+1] - bp[i]);
            return;
        }
    }
    i0 = n-2; frac = 1.0f;
}

// 1D linear interpolation: table[n_alpha]
inline float interp1(const float* bp, int nbp, const float* tbl, float a) {
    int i0; float fa;
    interp_idx(bp, nbp, a, i0, fa);
    return tbl[i0] * (1.0f - fa) + tbl[i0+1] * fa;
}

// 2D linear interpolation: table[n_alpha * n_beta], row-major (alpha varies fastest? No: MATLAB is column-major)
// MATLAB griddedInterpolant with reshape(data, [na, nb]) stores column-major.
// HDF5 stores row-major. So for a 2D table of shape (na*nb) flattened from (na,nb):
// index = ia + na * ib  (column-major from MATLAB reshape, but HDF5 flattens row-major)
// We need to check. From preprocess: reshape(data, L) where L=[len(alpha), len(beta)]
// MATLAB reshape is column-major: element (i,j) at index i + na*j
// HDF5 h5read returns same ordering. numpy reads as C-order by default but h5py preserves.
// Actually, h5py reads in the native HDF5 order which matches MATLAB column-major for .h5 written from MATLAB.
// Let's verify: Cy has shape (380,) = 20*19 = alpha1(20) x beta1(19). In column-major: idx = ia + 20*ib

inline float interp2(const float* bpa, int na, const float* bpb, int nb,
                     const float* tbl, float a, float b) {
    int ia, ib; float fa, fb;
    interp_idx(bpa, na, a, ia, fa);
    interp_idx(bpb, nb, b, ib, fb);
    // Column-major: tbl[ia + na*ib]
    float v00 = tbl[ia     + na * ib];
    float v10 = tbl[ia + 1 + na * ib];
    float v01 = tbl[ia     + na * (ib + 1)];
    float v11 = tbl[ia + 1 + na * (ib + 1)];
    float v0 = v00 * (1.0f - fa) + v10 * fa;
    float v1 = v01 * (1.0f - fa) + v11 * fa;
    return v0 * (1.0f - fb) + v1 * fb;
}

// 3D linear interpolation: table[na * nb * nc], column-major
// index = ia + na * (ib + nb * ic)
inline float interp3(const float* bpa, int na, const float* bpb, int nb, const float* bpc, int nc,
                     const float* tbl, float a, float b, float c) {
    int ia, ib, ic; float fa, fb, fc;
    interp_idx(bpa, na, a, ia, fa);
    interp_idx(bpb, nb, b, ib, fb);
    interp_idx(bpc, nc, c, ic, fc);
    auto idx = [&](int i, int j, int k) { return i + na * (j + nb * k); };
    float v000 = tbl[idx(ia,   ib,   ic)];
    float v100 = tbl[idx(ia+1, ib,   ic)];
    float v010 = tbl[idx(ia,   ib+1, ic)];
    float v110 = tbl[idx(ia+1, ib+1, ic)];
    float v001 = tbl[idx(ia,   ib,   ic+1)];
    float v101 = tbl[idx(ia+1, ib,   ic+1)];
    float v011 = tbl[idx(ia,   ib+1, ic+1)];
    float v111 = tbl[idx(ia+1, ib+1, ic+1)];
    float v00 = v000*(1-fa) + v100*fa;
    float v10 = v010*(1-fa) + v110*fa;
    float v01 = v001*(1-fa) + v101*fa;
    float v11 = v011*(1-fa) + v111*fa;
    float v0 = v00*(1-fb) + v10*fb;
    float v1 = v01*(1-fb) + v11*fb;
    return v0*(1-fc) + v1*fc;
}

// ============================================================
// High-level aero table lookup functions
// Signature matches MATLAB F16Aero.Cx(alpha, beta, ele) etc.
// All angles in DEGREES (as per MATLAB convention)
// ============================================================

// 3D tables: Cx(a,b,dh), Cz(a,b,dh), Cm(a,b,dh) use alpha1, beta1, dh1
inline float aero_Cx(float a, float b, float dh) {
    return interp3(ALPHA1, N_ALPHA1, BETA1, N_BETA1, DH1, N_DH1, TBL_Cx, a, b, dh);
}
inline float aero_Cz(float a, float b, float dh) {
    return interp3(ALPHA1, N_ALPHA1, BETA1, N_BETA1, DH1, N_DH1, TBL_Cz, a, b, dh);
}
inline float aero_Cm(float a, float b, float dh) {
    return interp3(ALPHA1, N_ALPHA1, BETA1, N_BETA1, DH1, N_DH1, TBL_Cm, a, b, dh);
}

// 3D tables: Cl(a,b,dh2), Cn(a,b,dh2) use alpha1, beta1, dh2
inline float aero_Cl(float a, float b, float dh) {
    return interp3(ALPHA1, N_ALPHA1, BETA1, N_BETA1, DH2, N_DH2, TBL_Cl, a, b, dh);
}
inline float aero_Cn(float a, float b, float dh) {
    return interp3(ALPHA1, N_ALPHA1, BETA1, N_BETA1, DH2, N_DH2, TBL_Cn, a, b, dh);
}

